1	const fs = require('fs');
2	const path = require('path');
3	const { test, expect } = require('@playwright/test');
4	
5	const USER_PASSWORD = 'E2EUser@Test12345!';
6	const ADMIN_ROTATED_PASSWORD = 'Admin@Rotated123456!';
7	
8	function loadBootstrapPassword() {
9	  const cfgPath = path.join(__dirname, '..', 'instance', 'config.json');
10	  if (!fs.existsSync(cfgPath)) {
11	    return null;
12	  }
13	  const raw = fs.readFileSync(cfgPath, 'utf8');
14	  const cfg = JSON.parse(raw);
15	  return cfg.ADMIN_BOOTSTRAP_PASSWORD || null;
16	}
