26	async function getAdminToken(request) {
27	  const bootstrapPassword = loadBootstrapPassword();
28	  let token = null;
29	  let usedPassword = null;
30	  let loginData = null;
31	
32	  const candidates = [];
33	  if (process.env.PEX_ADMIN_PASSWORD) {
34	    candidates.push(process.env.PEX_ADMIN_PASSWORD);
35	  }
36	  candidates.push(ADMIN_ROTATED_PASSWORD);
37	  if (bootstrapPassword) {
38	    candidates.push(bootstrapPassword);
39	  }
40	
41	  for (const candidate of candidates) {
42	    const { resp, data } = await login(request, 'admin', candidate);
43	    if (resp.ok()) {
44	      token = data.token;
45	      usedPassword = candidate;
46	      loginData = data;
47	      break;
48	    }
49	  }
50	
51	  if (!token) return null;
52	
53	  if (loginData.user && loginData.user.must_change_password) {
54	    const rotate = await request.post('/api/auth/change-password', {
55	      headers: { Authorization: `Bearer ${token}` },
56	      data: {
57	        current_password: usedPassword,
58	        new_password: ADMIN_ROTATED_PASSWORD,
59	      },
60	    });
61	    expect(rotate.ok()).toBeTruthy();
62	
63	    const relogin = await login(request, 'admin', ADMIN_ROTATED_PASSWORD);
64	    expect(relogin.resp.ok()).toBeTruthy();
65	    token = relogin.data.token;
66	  }
67	
68	  return token;
69	}
