106	      document: {
107	        name: 'doc.pdf',
108	        mimeType: 'application/pdf',
109	        buffer: Buffer.from('%PDF-1.4 smoke'),
110	      },
111	    },
112	  });
113	  if (submitVerification.status() === 201) {
114	    const verification = await submitVerification.json();
115	    const reviewResp = await request.put(
116	      `/api/verification/${verification.verification_id}/review`,
117	      {
118	        headers: adminHeaders,
119	        data: {
120	          decision: 'verified',
121	          notes: 'approved by Playwright smoke test',
122	        },
123	      },
124	    );
125	    expect(reviewResp.ok()).toBeTruthy();
126	  }
127	
128	  await page.goto('/');
129	  await page.fill('#l-user', username);
130	  await page.fill('#l-pass', USER_PASSWORD);
131	  await page.click('#btn-login');
132	  await expect(page.locator('#btn-logout')).toBeVisible();
133	
134	  await page.click('a[data-view="matching"]');
135	  await expect(page.locator('#btn-open-queue')).toBeVisible();
136	
137	  await page.click('#btn-open-queue');
138	  await page.fill('#q-skill', skill);
139	  await page.click('#queue-form button[type="submit"]');
140	
141	  const statusCard = page.locator('#match-status-card');
142	  await expect(statusCard).toBeVisible();
143	  await expect(statusCard).toContainText('Searching');
144	  await expect(statusCard).toHaveAttribute('hx-trigger', /every 10s/);
145	
146	  await page.click('#btn-logout');
147	  await expect(page.locator('#btn-login')).toBeVisible();
148	
